import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
});

// Add token to requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Mock data for frontend development
const mockExpenses = [
  {
    _id: '1',
    amount: 45.50,
    description: 'Lunch at Restaurant',
    category: 'Food',
    date: '2024-01-15T00:00:00.000Z',
    userId: 'user1'
  },
  {
    _id: '2',
    amount: 120.00,
    description: 'Monthly Bus Pass',
    category: 'Transport',
    date: '2024-01-10T00:00:00.000Z',
    userId: 'user1'
  },
  {
    _id: '3',
    amount: 89.99,
    description: 'Netflix Subscription',
    category: 'Entertainment',
    date: '2024-01-05T00:00:00.000Z',
    userId: 'user1'
  },
  {
    _id: '4',
    amount: 65.00,
    description: 'Groceries',
    category: 'Food',
    date: '2024-01-12T00:00:00.000Z',
    userId: 'user1'
  }
];

// Mock functions that will be replaced with real API calls
export const authAPI = {
  login: async (email, password) => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1000));
    
    // Mock response
    return {
      user: { name: 'Demo User', email },
      token: 'mock-jwt-token'
    };
  },
  
  register: async (userData) => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    
    return {
      user: { name: userData.name, email: userData.email },
      token: 'mock-jwt-token'
    };
  },
  
  verifyToken: async () => {
    await new Promise(resolve => setTimeout(resolve, 500));
    return { name: 'Demo User', email: 'demo@smartspend.com' };
  }
};

export const expenseAPI = {
  getAll: async () => {
    await new Promise(resolve => setTimeout(resolve, 800));
    return mockExpenses;
  },
  
  getRecent: async () => {
    await new Promise(resolve => setTimeout(resolve, 500));
    return mockExpenses.slice(0, 3);
  },
  
  create: async (expenseData) => {
    await new Promise(resolve => setTimeout(resolve, 600));
    const newExpense = {
      _id: Date.now().toString(),
      ...expenseData,
      date: new Date(expenseData.date).toISOString(),
      userId: 'user1'
    };
    mockExpenses.unshift(newExpense);
    return newExpense;
  },
  
  update: async (id, expenseData) => {
    await new Promise(resolve => setTimeout(resolve, 600));
    const index = mockExpenses.findIndex(exp => exp._id === id);
    if (index !== -1) {
      mockExpenses[index] = { ...mockExpenses[index], ...expenseData };
      return mockExpenses[index];
    }
    throw new Error('Expense not found');
  },
  
  delete: async (id) => {
    await new Promise(resolve => setTimeout(resolve, 500));
    const index = mockExpenses.findIndex(exp => exp._id === id);
    if (index !== -1) {
      mockExpenses.splice(index, 1);
      return { message: 'Expense deleted' };
    }
    throw new Error('Expense not found');
  },
  
  getDashboardStats: async () => {
    await new Promise(resolve => setTimeout(resolve, 700));
    const totalSpent = mockExpenses.reduce((sum, exp) => sum + exp.amount, 0);
    const expensesThisMonth = mockExpenses.length;
    
    // Find top category
    const categoryTotals = {};
    mockExpenses.forEach(exp => {
      categoryTotals[exp.category] = (categoryTotals[exp.category] || 0) + exp.amount;
    });
    const topCategory = Object.keys(categoryTotals).reduce((a, b) => 
      categoryTotals[a] > categoryTotals[b] ? a : b, 'Food');
    
    return {
      totalSpent,
      monthlyBudget: 3000,
      expensesThisMonth,
      topCategory
    };
  },
  
  getAnalytics: async (timeRange = '6months') => {
    await new Promise(resolve => setTimeout(resolve, 800));
    
    // Mock category data
    const categoryData = [
      { category: 'Food', total: 110.50 },
      { category: 'Transport', total: 120.00 },
      { category: 'Entertainment', total: 89.99 },
      { category: 'Shopping', total: 0 },
      { category: 'Bills', total: 0 },
      { category: 'Healthcare', total: 0 }
    ].filter(item => item.total > 0);
    
    // Mock monthly data
    const monthlyData = [
      { month: 'Aug', total: 800 },
      { month: 'Sep', total: 950 },
      { month: 'Oct', total: 720 },
      { month: 'Nov', total: 1100 },
      { month: 'Dec', total: 890 },
      { month: 'Jan', total: 320 }
    ];
    
    // Mock summary
    const summary = {
      topCategory: 'Food',
      avgMonthlySpend: 798,
      trend: -120
    };
    
    return {
      categoryData,
      monthlyData,
      summary
    };
  }
};

export default api;
